from math import isqrt
from sympy import factorint
def ok(n):
    f = factorint(n)
    if len(f) < 2 or max(f.values()) > 1: return False
    d = sum(n//p for p in f)
    return isqrt(d + 2*n)**2 == d + 2*n
print([n for n in range(2, 18000) if ok(n)])

